import React, { useState } from 'react';
import { Range } from '@salutejs/plasma-web';
export function App() {
    const [firstValue, setFirstValue] = useState('');
    const [secondValue, setSecondValue] = useState('');
    const [firstValueError, setFirstValueError] = useState(false);
    const [secondValueError, setSecondValueError] = useState(false);
    const [firstValueSuccess, setFirstValueSuccess] = useState(false);
    const [secondValueSuccess, setSecondValueSuccess] = useState(false);
    const validateRange = (first: string, second: string) => {
        const num1 = Number(first);
        const num2 = Number(second);
        setFirstValueError(false);
        setSecondValueError(false);
        setFirstValueSuccess(false);
        setSecondValueSuccess(false);
        if (first && second) {
            if (num1 >= num2) {
                setFirstValueError(true);
                setSecondValueError(true);
            } else {
                setFirstValueSuccess(true);
                setSecondValueSuccess(true);
            }
        }
    };
    const handleFirstChange = (e) => {
        const value = e.target.value;
        setFirstValue(value);
        validateRange(value, secondValue);
    };
    const handleSecondChange = (e) => {
        const value = e.target.value;
        setSecondValue(value);
        validateRange(firstValue, value);
    };
    return (
        <div>
            <Range
                firstValue={firstValue}
                secondValue={secondValue}
                label="Введите диапазон чисел"
                leftHelper="Первое число должно быть меньше второго"
                firstPlaceholder="Меньшее число"
                secondPlaceholder="Большее число"
                dividerVariant="dash"
                firstValueError={firstValueError}
                secondValueError={secondValueError}
                firstValueSuccess={firstValueSuccess}
                secondValueSuccess={secondValueSuccess}
                onChangeFirstValue={handleFirstChange}
                onChangeSecondValue={handleSecondChange}
            />
        </div>
    );
}

