import React from 'react';
import { Range, IconButton } from '@salutejs/plasma-web';
import { IconSearch, IconPlasma } from '@salutejs/plasma-icons';
export function App() {
    const ActionButton = () => (
        <IconButton view="clear" size="l">
            <IconSearch size="s" />
        </IconButton>
    );
    return (
        <div>
            <Range
                label="Диапазон с дополнительными элементами"
                leftHelper="Используйте кнопку для поиска"
                firstPlaceholder="От"
                secondPlaceholder="До"
                dividerVariant="dash"
                contentLeft={<IconPlasma size="s" color="inherit" />}
                contentRight={<ActionButton />}
                firstTextfieldContentLeft={<IconPlasma size="s" color="inherit" />}
                secondTextfieldContentRight={<IconPlasma size="s" color="inherit" />}
                firstTextfieldTextAfter="руб."
                secondTextfieldTextAfter="руб."
                stretch
            />
        </div>
    );
}

